// ============================================
// WELLNESSLIVING → HIGHLEVEL MAPPER
// Version: 5.2 - Enhanced Custom Field Mapping + Skip Non-Customer Webhooks
// Handles: Class bookings, purchases, profile updates, client creation
// Features: Smart tagging + Comprehensive custom field tracking
// ============================================

// DEBUG: Log the raw input structure
console.log('Raw $json keys:', Object.keys($json));
console.log('webhook_data type:', typeof $json.webhook_data);
console.log('webhook_data exists:', !!$json.webhook_data);

// Parse webhook_data from string to object
let webhookPayload = {};
try {
  if ($json.webhook_data && typeof $json.webhook_data === 'string') {
    webhookPayload = JSON.parse($json.webhook_data);
  } else if ($json.webhook_data && typeof $json.webhook_data === 'object') {
    webhookPayload = $json.webhook_data;
  }
} catch (error) {
  console.error('Error parsing webhook_data:', error.message);
  throw new Error('Failed to parse webhook_data: ' + error.message);
}

if (!webhookPayload || !webhookPayload.headers) {
  throw new Error('Invalid webhook_data structure. Expected headers and body.');
}

// Extract headers and body from the parsed webhook_data
const headers = webhookPayload.headers || {};
const body = webhookPayload.body || {};
const topic = headers['x-topic'] || 'unknown';

console.log('Topic detected:', topic);
console.log('Body keys:', Object.keys(body));

// ============================================
// SKIP NON-CUSTOMER WEBHOOKS
// ============================================
const nonCustomerWebhooks = [
  'purchase_option.created',
  'purchase_option.updated', 
  'purchase_option.deleted',
  'class.created',
  'class.updated',
  'class.deleted',
  'staff.created',
  'staff.updated',
  'staff.deleted'
];

if (nonCustomerWebhooks.includes(topic)) {
  console.log(`Skipping non-customer webhook: ${topic}`);
  // Return a minimal response that won't break the workflow
  return {
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    dateOfBirth: '',
    tags: ['skipped-webhook'],
    customField: {
      wl_webhook_skipped: topic,
      wl_skip_reason: 'No customer data in webhook'
    },
    debug: {
      topic: topic,
      skipReason: 'Non-customer webhook - no client data available'
    }
  };
}

console.log('Client data:', body.client);
console.log('Customer data:', body.a_customer);

// ============================================
// HELPER: Convert text to tag format
// ============================================
function toTag(text) {
  if (!text) return '';
  return text
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '') // Remove special characters except spaces and hyphens
    .replace(/\s+/g, '-') // Replace spaces with hyphens
    .replace(/-+/g, '-'); // Replace multiple hyphens with a single one
}

// ============================================
// HELPER: Format date to YYYY-MM-DD
// ============================================
function formatDate(dateString) {
  if (!dateString) return '';
  try {
    const date = new Date(dateString);
    if (isNaN(date.getTime())) {
      const parts = dateString.split(/[\s-:]+/);
      if (parts.length >= 3) {
        return `${parts[0]}-${parts[1].padStart(2, '0')}-${parts[2].padStart(2, '0')}`;
      }
      return dateString;
    }
    return date.toISOString().split('T')[0];
  } catch (e) {
    console.error('Error formatting date:', e.message, 'Original:', dateString);
    return dateString;
  }
}

// ============================================
// HELPER: Extract client data from multiple sources
// ============================================
function extractClientData(body, topic) {
  let client = {};
  let clientSource = 'unknown';

  // Handle different webhook types
  if (topic === 'client.created') {
    // Client creation webhooks - client data is directly in body
    client = body;
    clientSource = 'body (direct)';
  } else if (topic.startsWith('client.class.schedule')) {
    // Class bookings - usually in body.client
    client = body.client || {};
    clientSource = 'body.client';
  } else if (topic === 'purchase.created') {
    // Purchase webhooks - can be in body.client OR body.a_customer
    client = body.client || body.a_customer || {};
    clientSource = body.client ? 'body.client' : 'body.a_customer';
  } else {
    // Fallback - try all possible locations
    client = body.client || body.a_customer || body;
    clientSource = body.client ? 'body.client' : (body.a_customer ? 'body.a_customer' : 'body (direct)');
  }

  // Normalize client data structure
  const normalizedClient = {
    s_first_name: client.s_first_name || client.text_name?.split(' ')[0] || '',
    s_last_name: client.s_last_name || client.text_name?.split(' ').slice(1).join(' ') || '',
    s_mail: client.s_mail || client.text_mail || '',
    s_phone: client.s_phone || client.text_phone || '',
    dt_birth: client.dt_birth || '',
    uid: client.uid || '',
    s_member: client.s_member || '',
    dt_add: client.dt_add || '',
    is_customer_new: client.is_customer_new || false,
    has_discount: client.has_discount || false,
    text_login_type: client.text_login_type || '',
    a_custom_field: client.a_custom_field || [],
    a_member_group: client.a_member_group || [],
    attendance: client.attendance || {}
  };

  console.log('Client source:', clientSource);
  console.log('Normalized client:', normalizedClient);

  return { client: normalizedClient, clientSource };
}

// ============================================
// DEFENSIVE CLIENT DATA EXTRACTION
// ============================================
const { client, clientSource } = extractClientData(body, topic);
let additionalData = {};
let tags = [];
let customField = {};

// Extract client data based on topic
if (topic === 'client.created') {
  // New client creation
  tags.push('wl-client', 'new-client');

  // Add client type tag
  if (client.text_login_type) {
    tags.push(toTag(client.text_login_type));
  }

  // Add new customer tag if applicable
  if (client.is_customer_new) {
    tags.push('new-customer');
  }

  // Basic client information
  customField.wl_member_id = client.uid || '';
  customField.wl_member_since = formatDate(client.dt_add);
  customField.wl_member_status = client.text_login_type || '';
  customField.wl_client_type = client.text_login_type || '';
  customField.wl_has_discount = client.has_discount || false;

  additionalData = {
    memberId: client.uid,
    memberSince: client.dt_add,
    clientType: client.text_login_type,
    isNewCustomer: client.is_customer_new,
    hasDiscount: client.has_discount
  };

} else if (topic.startsWith('client.class.schedule')) {
  // Class bookings/cancellations/attendance
  tags.push('wl-client');

  const visitAction = body.id_visit?.value || '';
  const classTitle = body.s_title || '';
  const location = body.text_location || '';
  const instructor = body.a_staff?.[0]?.s_name || '';
  const bookingDate = formatDate(body.dt_date_local);

  if (visitAction === 'Book') {
    tags.push('class-booked', toTag(classTitle));
    customField.wl_last_class_booked = classTitle;
    customField.wl_last_class_date = bookingDate;
    customField.wl_last_booking_action = 'Book';
    customField.wl_last_booking_date = bookingDate;
  } else if (visitAction === 'Cancel') {
    tags.push('class-cancelled', toTag(classTitle));
    customField.wl_last_class_cancelled = classTitle;
    customField.wl_last_cancellation_date = bookingDate;
    customField.wl_last_booking_action = 'Cancel';
    customField.wl_last_booking_date = bookingDate;
  } else if (visitAction === 'Attend') {
    tags.push('class-attended', toTag(classTitle));
    customField.wl_last_class_attended = classTitle;
    customField.wl_last_attendance_date = bookingDate;
    customField.wl_last_booking_action = 'Attend';
    customField.wl_last_booking_date = bookingDate;
  }

  // Enhanced membership information
  if (client.attendance) {
    customField.wl_classes_remaining = client.attendance.i_left || null;
    customField.wl_membership_type = client.attendance.text_promotion || '';
    customField.wl_classes_total = client.attendance.i_total || null;
    customField.wl_classes_attended_count = client.attendance.i_use || null;

    // Purchase information
    if (client.attendance.o_purchase_item) {
      customField.wl_last_purchase_amount = client.attendance.o_purchase_item.m_cost_item || null;
      customField.wl_last_purchase_date = formatDate(client.attendance.o_purchase_item.dt_purchase);
      customField.wl_last_purchase_item = client.attendance.o_purchase_item.s_title || '';
    }

    // Add VIP tags based on membership value
    const membershipValue = parseFloat(client.attendance.o_purchase_item?.m_cost_item || 0);
    if (membershipValue >= 300) {
      tags.push('vip-300-plus', 'vip-member');
    } else if (membershipValue >= 200) {
      tags.push('vip-200-plus', 'vip-member');
    } else if (membershipValue >= 150) {
      tags.push('vip-150-plus', 'vip-member');
    }
  }

  // Additional client information
  customField.wl_member_id = client.uid || '';
  customField.wl_member_since = formatDate(client.dt_add);
  customField.wl_instructor_name = instructor;
  customField.wl_member_status = client.text_login_type || '';

  additionalData = {
    classTitle: classTitle,
    visitAction: visitAction,
    location: location,
    instructor: instructor,
    bookingDate: bookingDate,
    classesRemaining: client.attendance?.i_left || null,
    classesTotal: client.attendance?.i_total || null,
    classesUsed: client.attendance?.i_use || null,
    membershipType: client.attendance?.text_promotion || '',
    membershipValue: client.attendance?.o_purchase_item?.m_cost_item || null,
    memberSince: client.dt_add,
    memberId: client.uid
  };

} else if (topic === 'purchase.created') {
  // Purchase webhooks
  tags.push('wl-client', 'purchase-made');

  const purchase = body.purchase || {};
  const purchaseItems = body.purchase_items || [];

  if (purchase.amount) {
    customField.wl_last_purchase_amount = parseFloat(purchase.amount);
  }
  if (purchase.description) {
    customField.wl_last_purchase_item = purchase.description;
    tags.push(toTag(purchase.description));
  }
  if (purchase.date) {
    customField.wl_last_purchase_date = formatDate(purchase.date);
  }

  // Add VIP tags based on purchase amount
  const purchaseAmount = parseFloat(purchase.amount || 0);
  if (purchaseAmount >= 300) {
    tags.push('vip-300-plus', 'vip-member');
  } else if (purchaseAmount >= 200) {
    tags.push('vip-200-plus', 'vip-member');
  } else if (purchaseAmount >= 150) {
    tags.push('vip-150-plus', 'vip-member');
  }

  additionalData = {
    purchaseAmount: purchase.amount || null,
    purchaseCurrency: purchase.currency || '',
    purchaseDescription: purchase.description || '',
    purchaseDate: formatDate(purchase.date),
    paymentMethod: purchase.payment_method || '',
    purchaseStatus: purchase.status || '',
    purchaseItems: purchaseItems.map(item => ({
      title: item.title,
      price: item.price,
      quantity: item.quantity
    }))
  };

} else {
  // Fallback
  tags.push('wl-client', 'unknown-event');
}

// Ensure client has at least an email or phone for HighLevel
if (!client.s_mail && !client.s_phone) {
  console.error('No email or phone found for client:', client);
  throw new Error('No email or phone found for client in webhook payload.');
}

// Clean up tags (remove duplicates)
const uniqueTags = [...new Set(tags.filter(t => t))];

// ============================================
// BUILD HIGHLEVEL PAYLOAD
// ============================================
const result = {
  firstName: client.s_first_name || '',
  lastName: client.s_last_name || '',
  email: client.s_mail || '',
  phone: client.s_phone || '',
  dateOfBirth: formatDate(client.dt_birth),
  tags: uniqueTags,
  customField: customField,
  // Include additional data for debugging
  debug: {
    topic: topic,
    clientSource: clientSource,
    client: client,
    additionalData: additionalData,
    customFieldData: customField
  }
};

console.log('Final HighLevel payload:', JSON.stringify(result, null, 2));
console.log('Custom fields being sent:', JSON.stringify(customField, null, 2));

return result;

// Get all inputs
const inputs = $input.all();
console.log('Total inputs:', inputs.length);

// Find GET Contact data and Map WL → HL data
let getContactData = null;
let mapWLData = null;

inputs.forEach((input, index) => {
  const data = input.json;
  console.log(`Input ${index}:`, data);

  if (data.contacts && Array.isArray(data.contacts)) {
    getContactData = data;
    console.log(`Found GET Contact data in input ${index}`);
  }

  if (data.customField && Object.keys(data.customField).length > 0) {
    mapWLData = data;
    console.log(`Found Map WL → HL data in input ${index}`);
  }
});

// Get existing contact
const existingContact = getContactData?.contacts?.[0] || null;
const existingTags = existingContact ? (existingContact.tags || []) : [];

// Get new data
const newTags = mapWLData?.tags || [];
const customFieldData = mapWLData?.customField || {};

// ============================================
// PHONE CONFLICT PREVENTION
// ============================================
const existingPhone = existingContact?.phone || '';
const newPhone = mapWLData?.phone || '';
let phoneToUse = newPhone; // Default: use new phone
let conflictDetected = false;

if (existingContact && existingPhone && newPhone && existingPhone !== newPhone) {
  // Phone numbers differ - HighLevel may reject if new phone exists on another contact
  // STRATEGY: Preserve existing phone to avoid conflict
  phoneToUse = existingPhone;
  conflictDetected = true;
  console.warn(`⚠️ Phone conflict prevention: Keeping existing phone ${existingPhone} instead of new phone ${newPhone}`);

  // Log conflict info in custom fields for manual review
  customFieldData.wl_phone_conflict_detected = true;
  customFieldData.wl_phone_original = existingPhone;
  customFieldData.wl_phone_attempted = newPhone;
  customFieldData.wl_conflict_resolution = 'Preserved existing phone to prevent duplicate error';
} else if (existingContact && existingPhone && newPhone && existingPhone === newPhone) {
  // Same phone, no change
  phoneToUse = existingPhone;
} else if (!existingContact || !existingPhone) {
  // No existing contact or no existing phone - safe to use new phone
  phoneToUse = newPhone;
}

// Merge tags
const mergedTags = [...new Set([...existingTags, ...newTags])];

// Add notification tags if conflict detected
if (conflictDetected) {
  mergedTags.push('duplicate-contact-conflict');
  mergedTags.push('needs-manual-review');
  console.log('📢 Duplicate contact conflict detected - tags added for visibility');
}

console.log('Existing contact:', existingContact);
console.log('Existing phone:', existingPhone);
console.log('New phone:', newPhone);
console.log('Phone to use:', phoneToUse);
console.log('Conflict detected:', conflictDetected);
console.log('Merged tags:', mergedTags);
console.log('Custom field data:', customFieldData);

// Return the merged data (Code node format - NO array wrapper)
return {
  firstName: mapWLData?.firstName || existingContact?.firstName || '',
  lastName: mapWLData?.lastName || existingContact?.lastName || '',
  email: mapWLData?.email || existingContact?.email || '',
  phone: phoneToUse, // Use conflict-prevented phone
  dateOfBirth: mapWLData?.dateOfBirth || existingContact?.dateOfBirth || '',
  tags: mergedTags,
  contactId: existingContact ? existingContact.id : null,
  customField: customFieldData
};

// Get all inputs
const inputs = $input.all();
console.log('Total inputs:', inputs.length);

// Find the input with custom fields (this is what we want)
let finalData = null;

inputs.forEach((input, index) => {
  const data = input.json;
  console.log(`Input ${index}:`, data);

  // Use the input that has custom fields
  if (data.customField && Object.keys(data.customField).length > 0) {
    finalData = data;
    console.log(`Using data from input ${index} (has custom fields)`);
  }
});

// If no custom fields found, use the first item
if (!finalData && inputs.length > 0) {
  finalData = inputs[0].json;
  console.log('No custom fields found, using first item');
}

console.log('Final data:', finalData);

// Return ONLY ONE item
return finalData;

// Get output from Put node
const putNodeOutput = $input.first().json;
const contactData = $('Select best data').first().json;

// n8n stores errors when Continue on Fail is enabled
// Based on your error structure: errorMessage, errorDescription, errorDetails
let hasError = false;
let errorMessage = '';
let errorDescription = '';
let isDuplicateError = false;

// Helper function to extract clean error message from nested JSON strings
function extractCleanErrorMessage(rawError) {
  if (!rawError) return '';

  // Try to parse nested JSON strings
  try {
    // First level: might be "400 - \"{...}\""
    const match = rawError.match(/"message":\\?"([^"\\]+)"/);
    if (match) {
      return match[1].replace(/\\"/g, '"').replace(/\\n/g, ' ');
    }

    // Try to parse as JSON
    let parsed = rawError;
    for (let i = 0; i < 3; i++) { // Try up to 3 levels of JSON encoding
      try {
        parsed = JSON.parse(parsed);
        if (parsed.message) return parsed.message;
        if (typeof parsed === 'string') continue;
      } catch (e) {
        break;
      }
    }
  } catch (e) {
    // If parsing fails, return original
  }

  // Fallback: extract meaningful parts
  if (rawError.includes('duplicated contacts')) {
    return 'Duplicate contact error: Another contact already has this phone number.';
  }

  return rawError;
}

// Check for error indicators (n8n HTTP Request node error format)
if (putNodeOutput.errorMessage) {
  hasError = true;
  errorMessage = putNodeOutput.errorMessage || '';
  errorDescription = putNodeOutput.errorDescription || '';
} else if (putNodeOutput.error) {
  hasError = true;
  errorMessage = putNodeOutput.error.message || JSON.stringify(putNodeOutput.error);
  errorDescription = putNodeOutput.error.description || '';
}

// Extract clean, readable error message
const cleanErrorMessage = extractCleanErrorMessage(errorMessage);
const cleanDescription = extractCleanErrorMessage(errorDescription) || 'This location does not allow duplicated contacts.';

// Check if it's a duplicate contact error
if (hasError) {
  const errorText = (errorMessage + ' ' + errorDescription + ' ' + cleanErrorMessage).toLowerCase();
  isDuplicateError = errorText.includes('duplicate') || 
                     errorText.includes('duplicated contacts');
}

// Get contactId from contactData (should be from Select best data node)
const contactId = contactData.contactId;

// Format error log as readable text (not nested JSON)
const errorLogText = isDuplicateError ? 
  `⚠️ DUPLICATE CONTACT ERROR\n\n` +
  `Issue: ${cleanDescription}\n\n` +
  `Contact Details:\n` +
  `- Email: ${contactData.email || 'Not provided'}\n` +
  `- Phone: ${contactData.phone || 'Not provided'}\n` +
  `- Name: ${contactData.firstName || ''} ${contactData.lastName || ''}\n\n` +
  `Error occurred: ${new Date().toISOString()}\n\n` +
  `Action Required: Please review and manually merge duplicate contacts in HighLevel.` :
  null;

// Prepare output with error detection results
// Ensure isDuplicateError is explicitly a boolean (not string/truthy)
const output = {
  ...contactData, // Keep all original contact data
  hasError: Boolean(hasError),
  isDuplicateError: Boolean(isDuplicateError), // Explicitly convert to boolean
  errorMessage: errorMessage,
  errorDescription: errorDescription,
  contactId: contactId,
  // Prepare custom field update with error log (as readable text)
  duplicateErrorLog: errorLogText
};

console.log('Error Detection Results:', {
  hasError,
  isDuplicateError,
  errorMessage,
  contactId
});

return output;

// Get current data
const data = $json;

// Get existing tags and add error tag
const tags = [...(data.tags || []), 'needs-manual-merge'];

// Get existing custom fields
const existingCustomFields = Object.entries(data.customField || {}).map(([key, value]) => ({
  key: key,
  value: value
}));

// Add error log custom fields (only if duplicateErrorLog exists)
// Handle both old format (object) and new format (string)
let errorLogText = '';
if (data.duplicateErrorLog) {
  if (typeof data.duplicateErrorLog === 'string') {
    // Already formatted as clean text
    errorLogText = data.duplicateErrorLog;
  } else if (typeof data.duplicateErrorLog === 'object') {
    // Old format - convert to clean text
    errorLogText = 
      `⚠️ DUPLICATE CONTACT ERROR\n\n` +
      `Issue: This location does not allow duplicated contacts.\n\n` +
      `Contact Details:\n` +
      `- Email: ${data.duplicateErrorLog.email || data.email || 'Not provided'}\n` +
      `- Phone: ${data.duplicateErrorLog.phone || data.phone || 'Not provided'}\n` +
      `- Name: ${data.firstName || ''} ${data.lastName || ''}\n\n` +
      `Error occurred: ${data.duplicateErrorLog.date || new Date().toISOString()}\n\n` +
      `Action Required: Please review and manually merge duplicate contacts in FlowOs.`;
  }
}

const errorCustomFields = errorLogText ? [
  {
    key: 'wl_duplicate_error_log',
    value: errorLogText // Always a clean, readable string
  },
  {
    key: 'wl_last_error_date',
    value: new Date().toISOString()
  }
] : [];

// Combine all custom fields
const customFields = [...existingCustomFields, ...errorCustomFields];

// Build the payload
const payload = {
  firstName: data.firstName || '',
  lastName: data.lastName || '',
  email: data.email || '',
  dateOfBirth: data.dateOfBirth || '',
  tags: tags,
  customFields: customFields
};

return payload;

// WellnessLiving webhook validation - Robust version
// Handles all WellnessLiving webhook variations

const headers = $json.headers || {};
const body = $json.body || {};

// Required WellnessLiving headers (check both underscore and hyphen for flexibility)
const hasSignature = headers['x-signature-256'] || headers['x-signature_256'];
const hasTopic = headers['x-topic'] || headers['x_topic'];
const hasBusinessId = headers['x-business_id'] || headers['x-business-id']; // Check both
const hasPayloadKey = headers['x-payload-key'] || headers['x_payload_key'];
const hasUserAgent = headers['user-agent']?.includes('Wellnessliving.Webhook') || 
                     headers['user-agent']?.includes('WellnessLiving.Webhook');
const hasContentType = headers['content-type']?.includes('application/json') ||
                       headers['content-type']?.includes('application/json');

// Expected business ID
const expectedBusinessId = '340157';

// Get actual business ID (try both formats)
const actualBusinessId = headers['x-business_id'] || headers['x-business-id'];

// Log what we're checking (for debugging)
console.log('🔍 WellnessLiving Validation:');
console.log('  Signature:', hasSignature ? '✅' : '❌');
console.log('  Topic:', hasTopic || '❌ Missing');
console.log('  Business ID:', actualBusinessId || '❌ Missing');
console.log('  Payload Key:', hasPayloadKey ? '✅' : '❌');
console.log('  User Agent:', hasUserAgent ? '✅' : '❌');

// Validate required headers
if (!hasSignature) {
  throw new Error('Missing x-signature-256 header - request may be unauthorized');
}

if (!hasTopic) {
  throw new Error('Missing x-topic header - invalid WellnessLiving webhook');
}

if (!hasBusinessId) {
  throw new Error('Missing x-business_id header - invalid WellnessLiving webhook');
}

if (!hasPayloadKey) {
  throw new Error('Missing x-payload-key header - invalid WellnessLiving webhook');
}

if (!hasUserAgent) {
  throw new Error('Invalid user-agent - not from WellnessLiving');
}

if (!hasContentType) {
  throw new Error('Invalid content-type - expected application/json');
}

// Validate business ID matches expected
if (actualBusinessId && actualBusinessId !== expectedBusinessId) {
  throw new Error(`Invalid business ID: ${actualBusinessId} - expected ${expectedBusinessId}`);
}

// Validate body structure
if (!body || typeof body !== 'object' || Object.keys(body).length === 0) {
  throw new Error('Invalid webhook body - missing or empty');
}

// Optional: Validate topic is a known WellnessLiving topic pattern
const validTopicPatterns = [
  'client.created',
  'client.updated',
  'client.class.schedule',
  'purchase.created',
  'purchase.updated'
];

if (hasTopic) {
  const topicValid = validTopicPatterns.some(pattern => hasTopic.startsWith(pattern));
  if (!topicValid) {
    console.warn(`⚠️ Unknown webhook topic: ${hasTopic} - proceeding anyway`);
  }
